import { onMounted, onUnmounted, ref } from 'vue';

export function useAutoHidingNavbar({ hideDelayMs = 3000, triggerZoneHeight = 15, hoverZoneHeight = 60 } = {}) {
  const isNavbarVisible = ref(true);
  let hideTimeout = null;
  let mouseMoveHandler = null;

  function clearHideTimeout() {
    if (hideTimeout) {
      window.clearTimeout(hideTimeout);
      hideTimeout = null;
    }
  }

  function startHideTimeout() {
    clearHideTimeout();
    hideTimeout = window.setTimeout(() => {
      isNavbarVisible.value = false;
    }, hideDelayMs);
  }

  function handleMouseMove(event) {
    const inTriggerZone = event.clientY <= triggerZoneHeight;
    const hoveringNavbar = isNavbarVisible.value && event.clientY <= hoverZoneHeight;

    if (inTriggerZone || hoveringNavbar) {
      isNavbarVisible.value = true;
      clearHideTimeout();
      return;
    }

    if (isNavbarVisible.value && !hideTimeout) {
      startHideTimeout();
    }
  }

  function attach() {
    mouseMoveHandler = handleMouseMove;
    window.addEventListener('mousemove', mouseMoveHandler);
    startHideTimeout();
  }

  function detach() {
    if (mouseMoveHandler) {
      window.removeEventListener('mousemove', mouseMoveHandler);
      mouseMoveHandler = null;
    }
    clearHideTimeout();
  }

  onMounted(attach);
  onUnmounted(detach);

  return {
    isNavbarVisible,
    clearHideTimeout,
    startHideTimeout,
    handleMouseMove,
    attach,
    detach,
  };
}
