<script setup>
import { computed, onBeforeUnmount, onMounted, ref } from 'vue';
import { RouterLink, RouterView, useRoute } from 'vue-router';
import { useAppBootstrap } from './composables/useAppBootstrap';
import { useAutoHidingNavbar } from './composables/useAutoHidingNavbar';
import ThemeModeToggle from './components/ui/ThemeModeToggle.vue';
import apiClient from './api/client';
import {
  isGasLatencySimulationEnabled,
  setGasLatencySimulationEnabled,
} from './api/adapters/requestLatency';

const bootstrap = useAppBootstrap();
const { isNavbarVisible } = useAutoHidingNavbar();
const route = useRoute();
const isPreviewTransport = import.meta.env.VITE_AUTODRILLS_TRANSPORT === 'preview';
const isLocalTransport = import.meta.env.VITE_AUTODRILLS_TRANSPORT === 'local';
const showLatencyToggle = computed(() => !isPreviewTransport && import.meta.env.VITE_AUTODRILLS_TRANSPORT !== 'gas' && !(isLocalTransport && String(route.path || '').startsWith('/practice')));
const gasLatencySimulationEnabled = ref(isGasLatencySimulationEnabled());
const previewFocusMode = ref(typeof window !== 'undefined' ? window.localStorage.getItem('practice-focus-mode') === 'true' : false);
let devControlPollTimer = null;
let devControlRevision = null;

const previewNavItems = [
  { label: 'Practice', to: '/practice' },
  { label: 'About', to: '/about' },
  { label: 'Full Version', to: '/upgrade' },
];

const appBrandName = isPreviewTransport ? 'Autodrills Preview' : 'Autodrills Local';
const isPreviewNavbarFixed = computed(() => !isPreviewTransport || previewFocusMode.value);
const canShowAdminNav = computed(() => Boolean(bootstrap.user.value?.isAdmin));
const activeNavItems = computed(() => {
  if (isPreviewTransport) {
    return previewNavItems;
  }
  const baseItems = [
    { label: 'Practice', to: '/practice' },
    { label: 'About', to: '/about' },
  ];
  if (canShowAdminNav.value) {
    baseItems.push(
      { label: 'Admin', to: '/admin/drills' },
      { label: 'Analytics', to: '/admin/analytics' },
    );
  }
  return baseItems;
});

function toggleGasLatencySimulation() {
  gasLatencySimulationEnabled.value = !gasLatencySimulationEnabled.value;
  setGasLatencySimulationEnabled(gasLatencySimulationEnabled.value);
}

function handlePreviewFocusModeChange(event) {
  previewFocusMode.value = Boolean(event?.detail);
}

async function pollDevControlRevision() {
  if (!isLocalTransport || typeof window === 'undefined') {
    return;
  }
  try {
    const status = await apiClient.fetchDevStatus();
    const revision = String(status?.currentUserRevision || '');
    if (!revision) {
      return;
    }
    if (!devControlRevision) {
      devControlRevision = revision;
      return;
    }
    if (revision !== devControlRevision) {
      devControlRevision = revision;
      window.location.reload();
    }
  } catch {
    if (devControlPollTimer) {
      window.clearInterval(devControlPollTimer);
      devControlPollTimer = null;
    }
  }
}

onMounted(() => {
  document.title = appBrandName;
  if (isPreviewTransport && typeof window !== 'undefined') {
    window.addEventListener('autodrills-focus-mode-change', handlePreviewFocusModeChange);
  }
  if (isLocalTransport && typeof window !== 'undefined') {
    void pollDevControlRevision();
    devControlPollTimer = window.setInterval(() => {
      void pollDevControlRevision();
    }, 3000);
  }
  void bootstrap.loadBootstrap();
});

onBeforeUnmount(() => {
  if (isPreviewTransport && typeof window !== 'undefined') {
    window.removeEventListener('autodrills-focus-mode-change', handlePreviewFocusModeChange);
  }
  if (devControlPollTimer) {
    window.clearInterval(devControlPollTimer);
    devControlPollTimer = null;
  }
});
</script>

<template>
  <div class="app-shell">
    <!-- Navbar Trigger Zone (invisible) -->
    <div v-if="isPreviewNavbarFixed" class="navbar-trigger" />

    <nav 
      class="navbar navbar-expand-lg bg-body border-bottom shadow-sm"
      :class="{
        'navbar-hidden': isPreviewTransport ? (previewFocusMode && !isNavbarVisible) : !isNavbarVisible,
        'navbar-preview-static': isPreviewTransport && !previewFocusMode,
      }"
    >
      <div class="container">
        <RouterLink class="navbar-brand fw-semibold preview-brand" to="/practice">
          <span class="brand-name">{{ appBrandName }}</span>
        </RouterLink>
        <div class="d-flex align-items-center gap-3">
          <div class="nav nav-pills">
            <RouterLink
              v-for="item in activeNavItems"
              :key="item.to"
              class="nav-link"
              :to="item.to"
              active-class="active"
            >
              {{ item.label }}
            </RouterLink>
          </div>
          <button
            v-if="showLatencyToggle"
            class="btn btn-sm"
            :class="gasLatencySimulationEnabled ? 'btn-warning' : 'btn-outline-secondary'"
            :aria-pressed="gasLatencySimulationEnabled"
            title="Toggle GAS latency simulation"
            @click="toggleGasLatencySimulation"
          >
            <i class="bi" :class="gasLatencySimulationEnabled ? 'bi-hourglass-split' : 'bi-hourglass'"></i>
            <span class="ms-1 d-none d-md-inline">
              {{ gasLatencySimulationEnabled ? 'GAS delays on' : 'GAS delays off' }}
            </span>
          </button>
          <ThemeModeToggle />
          <div v-if="!isPreviewTransport" class="small text-muted text-end">
            <div>{{ bootstrap.user.value?.name || 'Loading user...' }}</div>
          </div>
        </div>
      </div>
    </nav>

    <main class="container py-4 flex-grow-1">
      <div v-if="bootstrap.loading.value && !bootstrap.error.value" class="text-center py-5 text-muted small">
        <div class="spinner-border spinner-border-sm me-2" role="status"></div>
        Bootstrapping environment...
      </div>

      <div v-if="bootstrap.error.value" class="alert alert-danger">
        {{ bootstrap.error.value }}
      </div>

      <RouterView />
    </main>
  </div>
</template>

