const SESSION_STORAGE_KEY = 'autodrills.simulate-gas-latency';

function isSessionStorageAvailable() {
  return typeof window !== 'undefined' && typeof window.sessionStorage !== 'undefined';
}

function isGasLatencySimulationEnabled() {
  if (!isSessionStorageAvailable()) {
    return false;
  }
  return window.sessionStorage.getItem(SESSION_STORAGE_KEY) === 'true';
}

function setGasLatencySimulationEnabled(enabled) {
  if (!isSessionStorageAvailable()) {
    return;
  }
  window.sessionStorage.setItem(SESSION_STORAGE_KEY, enabled ? 'true' : 'false');
}

function randomDelay(minMs, maxMs) {
  const lower = Math.max(0, Number(minMs) || 0);
  const upper = Math.max(lower, Number(maxMs) || lower);
  return Math.round(lower + Math.random() * (upper - lower));
}

function classifyLatencyBucket(path = '', method = 'GET') {
  const upperPath = String(path).toLowerCase();
  const upperMethod = String(method || 'GET').toUpperCase();

  if (upperPath.includes('/api/meta/bootstrap')) {
    return 'bootstrap';
  }
  if (upperPath.includes('/api/meta/') || upperPath.includes('/api/analytics/student')) {
    return 'catalog';
  }
  if (upperPath.includes('/api/analytics/teacher')) {
    return 'analytics';
  }
  if (upperPath.includes('/api/practice/session/start') || upperPath.includes('/api/practice/session/slice')) {
    return 'session';
  }
  if (upperPath.includes('/api/practice/response')) {
    return 'response';
  }
  if (upperPath.includes('/api/practice/report')) {
    return 'report';
  }
  if (upperPath.includes('/api/admin/')) {
    return 'admin';
  }
  if (upperMethod === 'POST' || upperMethod === 'PUT' || upperMethod === 'DELETE') {
    return 'mutation';
  }
  return 'default';
}

function getSimulatedDelayMs(path, method) {
  switch (classifyLatencyBucket(path, method)) {
    case 'bootstrap':
      return randomDelay(700, 1400);
    case 'catalog':
      return randomDelay(500, 1200);
    case 'analytics':
      return randomDelay(600, 1500);
    case 'session':
      return randomDelay(800, 2000);
    case 'response':
      return randomDelay(500, 1200);
    case 'report':
      return randomDelay(500, 1000);
    case 'admin':
      return randomDelay(500, 1400);
    case 'mutation':
      return randomDelay(500, 1000);
    default:
      return randomDelay(250, 750);
  }
}

async function maybeSimulateLatency(path, method) {
  if (!isGasLatencySimulationEnabled()) {
    return;
  }
  const delayMs = getSimulatedDelayMs(path, method);
  await new Promise((resolve) => window.setTimeout(resolve, delayMs));
}

export {
  SESSION_STORAGE_KEY,
  classifyLatencyBucket,
  getSimulatedDelayMs,
  isGasLatencySimulationEnabled,
  maybeSimulateLatency,
  setGasLatencySimulationEnabled,
};
