<script setup>
import { useThemeMode } from '../../composables/useThemeMode';

const { preference, setPreference } = useThemeMode();

const themes = [
  { value: 'light', label: 'Light', icon: 'bi-sun' },
  { value: 'dark', label: 'Dark', icon: 'bi-moon-stars' },
  { value: 'system', label: 'System', icon: 'bi-display' },
];

const getActiveIcon = () => {
  return themes.find(t => t.value === preference.value)?.icon || 'bi-circle-half';
};
</script>

<template>
  <div class="dropdown theme-mode-toggle">
    <button
      class="btn btn-link nav-link dropdown-toggle d-flex align-items-center p-0 border-0"
      type="button"
      data-bs-toggle="dropdown"
      aria-expanded="false"
      title="Toggle theme"
    >
      <i class="bi" :class="getActiveIcon()"></i>
      <span class="ms-2 d-lg-none">Theme</span>
    </button>
    <ul class="dropdown-menu dropdown-menu-end shadow-sm">
      <li v-for="theme in themes" :key="theme.value">
        <button
          class="dropdown-item d-flex align-items-center gap-2"
          :class="{ active: preference === theme.value }"
          type="button"
          @click="setPreference(theme.value)"
        >
          <i class="bi" :class="theme.icon"></i>
          {{ theme.label }}
        </button>
      </li>
    </ul>
  </div>
</template>

<style scoped>
.theme-mode-toggle :deep(.dropdown-toggle::after) {
  display: none;
}

.theme-mode-toggle .btn-link {
  color: var(--bs-secondary-color);
  text-decoration: none;
}

.theme-mode-toggle .btn-link:hover {
  color: var(--bs-primary);
}

.dropdown-item.active {
  background-color: var(--bs-primary);
}

.dropdown-item i {
  width: 1.25rem;
  text-align: center;
}
</style>
